                      required 
                      className={inputClasses}
                      value={editingEqId ? (editEqForm.category || '') : newEq.category} 
                      onChange={e => editingEqId ? setEditEqForm({...editEqForm, category: e.target.value}) : setNewEq({...newEq, category: e.target.value})} 
